// // This module implements a 5-bit register with synchronous clear and disable load enable signals.
module Register5bit (
    input clk,
    input clr,
    input load,
    input [4:0] in,
    output reg [4:0] out
);

    always @(posedge clk or posedge clr) begin
        if (clr) begin
            out <= 5'b00000;
        end else if (load) begin
            out <= in;
        end
    end
endmodule
